// ============================================================
// InitCore v1.0 — Validación de firma X-Twilio-Signature
// Algoritmo oficial de Twilio:
//   1. Concatenar URL completa del webhook
//   2. Ordenar alfabéticamente los parámetros POST
//   3. Concatenar clave+valor (sin separador) en orden
//   4. HMAC-SHA1 con el Auth Token de Twilio
//   5. Base64 del resultado → comparar con header X-Twilio-Signature
// ============================================================

const crypto = require('crypto');

const authToken = $env.TWILIO_AUTH_TOKEN;
if (!authToken) {
  throw new Error('TWILIO_AUTH_TOKEN no está definido en variables de entorno');
}

const signatureHeader = $input.first().json.headers['x-twilio-signature']
  || $input.first().json.headers['X-Twilio-Signature'];

if (!signatureHeader) {
  return [{ json: { valid: false, reason: 'Header X-Twilio-Signature ausente', status: 'rejected' } }];
}

// URL pública donde Twilio envió el POST (debe coincidir EXACTAMENTE)
const webhookUrl = $env.TWILIO_WEBHOOK_URL || 'https://tu-dominio.com/webhook/initcore/whatsapp';

// Twilio envía form-urlencoded; n8n lo parsea en body
const body = $input.first().json.body || {};

// Ordenar claves alfabéticamente y concatenar key+value
const sortedKeys = Object.keys(body).sort();
let dataToSign = webhookUrl;
for (const key of sortedKeys) {
  dataToSign += key + body[key];
}

// HMAC-SHA1 y base64
const computed = crypto
  .createHmac('sha1', authToken)
  .update(Buffer.from(dataToSign, 'utf-8'))
  .digest('base64');

const valid = crypto.timingSafeEqual(
  Buffer.from(computed),
  Buffer.from(signatureHeader)
);

if (!valid) {
  return [{
    json: {
      valid: false,
      reason: 'Firma Twilio inválida',
      status: 'rejected',
      computed,
      received: signatureHeader
    }
  }];
}

return [{ json: { ...body, valid: true, headers: $input.first().json.headers } }];

const crypto = require('crypto');
const sha256 = s => crypto.createHash('sha256').update(String(s),'utf-8').digest('hex');
const stripHtml = html => !html ? '' : String(html)
  .replace(/<script[\s\S]*?<\/script>/gi,'')
  .replace(/<style[\s\S]*?<\/style>/gi,'')
  .replace(/<\/?[^>]+>/g,'')
  .replace(/&nbsp;/gi,' ').replace(/&amp;/gi,'&').replace(/&lt;/gi,'<')
  .replace(/&gt;/gi,'>').replace(/&quot;/gi,'"').replace(/&#39;|&apos;/gi,"'")
  .replace(/\s+/g,' ').trim();
const normForHash = t => (t||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^\p{L}\p{N}]+/gu,' ').replace(/\s+/g,' ').trim();

// ============================================================
// InitCore v1.0 — Extracción y normalización desde Twilio
// Convierte payload Twilio → formato unificado InitCore
// ============================================================

const data = $input.first().json;

// Extraer número (From viene como 'whatsapp:+34666123456')
const fromRaw = data.From || '';
const phone = fromRaw.replace('whatsapp:', '').trim();

// Construir array de media (Twilio numera MediaUrl0, MediaUrl1, ...)
const numMedia = parseInt(data.NumMedia || '0', 10);
const media = [];
for (let i = 0; i < numMedia; i++) {
  const url = data[`MediaUrl${i}`];
  const type = data[`MediaContentType${i}`] || 'application/octet-stream';
  if (url) media.push({ url, type });
}

// Truncar texto a 5000 chars según spec InitCore
const text = (data.Body || '').toString().substring(0, 5000);

// Payload parcial — el core se encarga de UUID, hash SHA-256 del user, dedupe, etc.
const payload = {
  channel: 'whatsapp',
  message: {
    text,
    media
  },
  timestamp: new Date().toISOString(),
  context: {
    name: data.ProfileName || '',
    email: '',
    phone,
    language: 'es'
  },
  metadata: {
    source: 'whatsapp_adapter',
    adapter_version: '1.0.0',
    twilio_message_sid: data.MessageSid || '',
    twilio_account_sid: data.AccountSid || '',
    raw_from: fromRaw
  },
  status: 'pending',
  // El core usará este campo para generar user_id = sha256(channel + phone)
  _user_identifier: phone
};


const message_id = crypto.randomUUID();
const sender_id = sha256(payload.channel + ':' + payload._user_identifier);
const cleanText = stripHtml(payload.message?.text || '');
const mediaFingerprint = (payload.message?.media||[]).map(m => m.url || m.file_id || '').join('|');
const hashKey = normForHash(cleanText);
const hash = sha256(payload.channel + ':' + sender_id + ':' + (hashKey || mediaFingerprint || message_id));

// Flatten out the response so it is easy to persist to messages table, AND hold the 5 fields
const newPayload = {
  channel: payload.channel,
  message_id: message_id,
  sender_id: sender_id,
  user_id: sender_id, // keep it around for the messages table insert
  text: cleanText,
  hash: hash,
  media: payload.message?.media || [],
  ts: payload.timestamp || new Date().toISOString(),
  context: payload.context || {},
  metadata: payload.metadata || {}
};

return [{ json: newPayload }];

// ============================================================
// Handler de error — registra en tabla `errors` y responde 500
// ============================================================
const err = $input.first().json;
return [{
  json: {
    channel: 'whatsapp',
    error_message: err.error?.message || 'Error desconocido en WhatsApp adapter',
    error_stack: err.error?.stack || '',
    payload: err,
    timestamp: new Date().toISOString(),
    retry_count: err.$execution?.retryCount || 0
  }
}];
